SELECT * FROM activity WHERE deleted = 0
 AND activity_id = #{activityId} 
 AND activity_name LIKE CONCAT('%', #{activityName}, '%') 

    AND (
        activity_name LIKE CONCAT('%', REPLACE(REPLACE(REPLACE(#{searchParam}, '\\', '\\\\'), '%', '\\%'), '_', '\\_'), '%') ESCAPE '\\'
        OR activity_desc LIKE CONCAT('%', REPLACE(REPLACE(REPLACE(#{searchParam}, '\\', '\\\\'), '%', '\\%'), '_', '\\_'), '%') ESCAPE '\\'
    )

 AND create_user_id = #{createUserId} 
 AND status = #{status} 
ORDER BY activity_id DESC
LIMIT #{page}, #{limit}

